"""
MABE Bootstrap: Shell Library + Multi-Shell Compositor

Run: python3 bootstrap_multi_shell.py

Prerequisites:
  - optical/ M1-M9 foundation
  - optical/coordination_optics_bridge.py (M4a)
  - optical/structural_dye.py
  - optical/core_shell_mie.py (Bohren-Huffman version)
  - core/scorer_frozen.py
  - pip install miepython scipy numpy

Creates 3 files:
  optical/shell_library.py            — 11 chromophores + 6 index shells
  optical/multi_shell.py              — Multi-shell compositor + 5 design presets
  tests/test_optical/test_multi_shell.py — 20 tests

Shell categories:
  Chromophores: CuPc, ZnPc, TPP, ZnTPP, CuTPP, Ru(bpy)3, disperse_red_1,
                methyl_orange, fluorescein, rhodamine_B, indigo
  Index mods:   porous_silica_30, porous_silica_50, PMMA_brush,
                TiO2_solgel, ZnO_solgel, polydopamine

Design presets (all click-orthogonal):
  red_attack:     porous_silica → CuPc          (SPAAC → thiol-maleimide)
  hi_sat_green:   CuPc → TPP                    (SPAAC → thiol-maleimide)
  warm_gold:      TPP → polydopamine             (SPAAC → thiol-maleimide)
  index_sandwich: porous_silica → TiO2_solgel    (SPAAC → thiol-maleimide)
  triple_stack:   porous_silica → CuPc → PMMA   (SPAAC → thiol-mal → IEDDA)

Gamut achieved: 406nm (violet) to 608nm (orange) on SiO2 cores.
"""
import base64, pathlib

FILES = {
    "optical/shell_library.py": "",
    "optical/multi_shell.py": "",
    "tests/test_optical/test_multi_shell.py": "",

}

def main():
    print()
    print("  MABE Shell Library + Multi-Shell Compositor Bootstrap")
    print("  " + "=" * 54)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_optical/test_multi_shell.py -v")
    print()

if __name__ == "__main__":
    main()